<template>
  <div id="app">
    <div class="container-fluid">
      <div class="row">
        <div class="col-xs-12 col-md-6 col-md-offset-3 text-center padding-to">
          <div class="panel panel-default compute">
            <div class="panel-body">
              <button class="btn btn-info" @click="timelineLoad">Load Workspaces</button>
              <button class="btn btn-info" @click="timelineSave">Save All Workspaces</button>
              <button class="btn btn-info" @click="timelineRemove">Remove Workspaces</button>
            </div>
          </div>
        </div>
      </div>
      <div class="row app-container">
        <div class="col-md-12">
          <router-view :key="$route.fullPath"></router-view>
        </div>
      </div>

      <nav class="navbar navbar-fixed-bottom">
        <div class="navbar-left">
          <router-link class="nav-icons nav-large-icon nav-home-icon" to="/"><i class="fa fa-home"></i></router-link>
          <a class="nav-icons nav-large-icon nav-context-icon" @click.prevent="openContext"><i class="fa fa-list"></i></a>
        </div>
        
        <draggable class="nav navbar-nav dragArea" :element="'ul'" role="tablist" :list="timelines" :options="draggableOptions" @end="onEndDrag">
          <li v-for="(t, index, key) in timelines" :key="key" class="draggable">
            <router-link :to="`/timeline/${t}`">
              <span :id="t" :contenteditable="contentEditable" @input="updateTimelineName" @dblclick="changeContentEditable(true)" @blur="changeContentEditable(false)">{{timelineTitles[index]}}</span> <span class="nav-remove-timeline" @click="removeTimeline(t)"><i class="fa fa-close"></i></span>
            </router-link>
          </li>
        </draggable>

        <div class="navbar-left">
          <a class="nav-icons nav-add-icon" @click.prevent="openAddTimelineModal"><i class="fa fa-plus"></i></a>
        </div>
      </nav>
    </div>

    <context-menu id="context-menu" ref="ctxMenu">
      <li v-for="(t, index, key) in timelines" :key="key" @click="navigateTo(`/timeline/${t}`)">
        <a v-html="timelineTitles[index]"></a>
      </li>
    </context-menu>

    <div class="modal fade" id="timelineModal" tabindex="-1" role="dialog" aria-labelledby="myModalLabel">
      <div class="modal-dialog" role="document">
        <div class="modal-content">
          <div class="modal-header">
            <button type="button" class="close" data-dismiss="modal" aria-label="Close"><span aria-hidden="true">&times;</span></button>
            <h4 class="modal-title" id="myModalLabel">Add Worksheet</h4>
          </div>
          <div class="modal-body">
            <div class="row">
              <div class="col-md-12">
                <div class="form-group">
                  <label :for="uid">UID</label>
                  <input type="text" class="form-control" placeholder="UID" :value="uid" @input="updateUid">
                </div>
                <div class="form-group">
                  <label :for="table">Open Table</label>
                  <input type="text" class="form-control" placeholder="Open Table" :value="table" @input="updateTable">
                </div>
              </div>
            </div>
          </div>
          <div class="modal-footer">
            <button type="button" class="btn btn-default" data-dismiss="modal">Cancel</button>
            <button type="button" class="btn btn-primary" @click="createTimeline">Add</button>
          </div>
        </div>
      </div>
    </div>

    <div class="modal fade" id="confirmModal" tabindex="-1" role="dialog" aria-labelledby="myRemoveLabel">
      <div class="modal-dialog" role="document">
        <div class="modal-content">
          <div class="modal-header">
            <button type="button" class="close" data-dismiss="modal" aria-label="Close"><span aria-hidden="true">&times;</span></button>
            <h4 class="modal-title" id="myModalLabel">Are you sure?</h4>
          </div>
          <div class="modal-body">
            Are you sure you want to delete this worksheet?
          </div>
          <div class="modal-footer">
            <button type="button" class="btn btn-default" data-dismiss="modal">Cancel</button>
            <button type="button" class="btn btn-danger" @click="removeTimelineConfirmed">Yes remove!</button>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { mapMutations } from 'vuex'
import contextMenu from 'vue-context-menu'
import draggable from 'vuedraggable'

const jQuery = window.jQuery

export default {
  name: 'app',
  dependencies: { discoveryApi: 'DiscoveryApi' },
  components: {
    contextMenu,
    draggable
  },
  data: () => {
    return {
      addModal: null,
      contentEditable: false,
      draggableOptions: {
        draggable: '.draggable'
      },
      removeId: undefined,
      removeModal: null,
      timelineTitles: []
    }
  },
  computed: {
    latestTimelineId () {
      return this.$store.state.indexer
    },
    table () {
      return this.$store.state.table
    },
    timelines: {
      get () {
        return this.$store.state.timelines
      },
      set (val) {
        this.$store.commit('updateTimelines', val)
      }
    },
    uid () {
      return this.$store.state.uid
    }
  },
  mounted () {
    // assign add modal elem
    this.addModal = jQuery(this.$el.children.timelineModal)
    this.removeModal = jQuery(this.$el.children.confirmModal)

    // load initial saved timeline(s)
    this.timelineLoad()

    var self = this
    this.$nextTick(() => {
      self.$bus.$on('createWorkbook', () => {
        self.openAddTimelineModal()
      })
      // set titles after load
      self.updateAllTimelineTitles()
    })
  },
  methods: {
    changeContentEditable (editable) {
      this.contentEditable = editable
    },
    createTimeline () {
      this.addTimeline()
      var self = this
      this.$nextTick(() => {
        // update titles
        self.updateAllTimelineTitles()

        self.addModal.modal('hide')
        // todo: navigate to new tab.
        self.$router.push({ path: `/timeline/${self.latestTimelineId}` })
      })
    },
    navigateTo (url) {
      this.$router.push({ path: url })
    },
    navigateToFirstVisible () {
      if (this.timelines && this.timelines.length > 0) {
        this.$router.push({ path: `/timeline/${this.timelines[0]}` })
      } else {
        this.$router.push('/')
      }
    },
    onEndDrag () {
      this.updateAllTimelineTitles()
    },
    openAddTimelineModal () {
      this.addModal.modal('show')
    },
    openContext () {
      if (this.timelines && this.timelines.length > 0) {
        this.$refs.ctxMenu.open()
      }
    },
    removeTimelineConfirmed () {
      var self = this
      this.removeModal.modal('hide')
      this.$nextTick(() => {
        self.$store.commit('removeTimeline', self.removeId)
        self.$nextTick(() => {
          if (self.$route.params.id - 0 === self.removeId) {
            self.navigateToFirstVisible()
          }

          self.removeId = undefined
        })

        self.updateAllTimelineTitles()
      })
    },
    removeTimeline (id) {
      this.removeId = id
      this.removeModal.modal('show')
    },
    timelineLoad () {
      var self = this
      this.discoveryApi.workspaceLoad(this.uid).then(res => {
        if (res.status === 200) {
          // clear existings timelines
          self.removeAllTimelines()

          if (res.data.timelines && res.data.timelines.length > 0) {
            // create new timeline with data
            res.data.timelines.forEach(t => {
              self.addTimeline(t)
            })

            // debugger
            // self.$toastr.info(`Workspace Loaded (${res.data.duration})`, 'Title')
          } else {
            // alert no data to be loaded
          }

          self.updateAllTimelineTitles()
          self.navigateToFirstVisible()
          // emit event after successfully loading.
          self.$bus.$emit('loadDefaultTimeline')
        } else {
          // alert failed to load
        }
      })
    },
    timelineSave () {
      var timelines = this.$store.getters.allTimelines
      if (timelines && timelines.length > 0) {
        this.discoveryApi.workspaceSave(timelines).then(res => {
          if (res.status === 200) {
            // alert save
          } else {
            // alert save failed
          }
        })
      }
    },
    timelineRemove () {
      var self = this
      this.discoveryApi.workspaceRemove(this.uid).then(res => {
        if (res.status === 200) {
          self.removeAllTimelines()
          // alert removed
        } else {
          // alert removed failed
        }
      })
    },
    updateAllTimelineTitles () {
      var self = this
      // when timeline ids are updated we need to update the titles
      this.$nextTick(() => {
        self.timelineTitles = self.timelines.map(t => {
          return self.$store.getters[`timelineModule${t}/timeline`].name || 'name not found'
        })
      })
    },
    updateTable (e) {
      this.$store.commit('updateTable', e.target.value)
    },
    updateTimelineName (e) {
      clearTimeout(this.timelineNameChange)

      var self = this
      this.timelineNameChange = setTimeout(() => {
        // need a cleaner way to call the update name
        self.$store._mutations[`timelineModule${e.target.id}/updateTimelineName`][0](e.target.innerText)
      }, 400)
    },
    updateUid (e) {
      this.$store.commit('updateUid', e.target.value)
    },
    ...mapMutations([
      'addTimeline',
      'removeAllTimelines',
      'increment'
    ])
  }
}
</script>

<style lang="scss">
  @import '../styles/main.scss';
  
  html, body {
    margin: 0 auto;
    padding: 0;
  }
  #app {
    font-family: 'Avenir', Helvetica, Arial, sans-serif;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    color: #2c3e50;
    padding-top:20px;
  }
  .tab-container {
    padding-top: 15px;
  }
  .padding-left-5 {
    padding-left: 5px;
  }
</style>


