<template>
  <div>
    <h1>Home Page</h1>
    <button class="btn btn-primary" @click="createWorkbook">Create Work Book</button>
  </div>
</template>

<script>
  export default {
    name: 'home',
    methods: {
      createWorkbook () {
        this.$bus.$emit('createWorkbook')
      }
    }
  }
</script>

