import Models from '../utilities/componentModels'
import { store } from '../store'

export default class Timeline {
  constructor (uid, table, name) {
    this._currentId = 1

    this.uid = uid
    this.name = name || 'Workspace ' + this._currentId
    this.ops = []
    this.columns = []

    this.add('OpenTable', { table })
  }

  createFromSource (timeline) {
    Object.assign(this, timeline)
  }

  getNextId () {
    return this._currentId++
  }

  setNextId (id) {
    this._currentId = id
  }

  add (opType, options) {
    var op = new Models[opType](options)

    op.id = this.getNextId()

    // Set the new rule after the id of op has been set
    if (opType === 'Select') {
      this.addRule(op)
    }

    this.ops.push(op)
  }

  remove (op) {
    this.ops = this.ops.filter(o => {
      return o.id !== op.id
    })
  }

  addRule (op) {
    var rule = new Models['SelectRule']()
    rule.id = this.getNextId()

    if (op) {
      op.data.rules.push(rule)
    }

    return rule
  }

  removeRule (op, rule) {
    op.data.rules = op.data.rules.filter(r => {
      return r.id !== rule.id
    })
  }

  setOperations (timeline) {
    if (!timeline) {
      return
    }

    var self = this

    var ops = timeline.ops
    self.name = timeline.name

    self.ops = ops.map(op => {
      var operation = new Models[op.op](op).createFromSource(op)
      if (op.op === 'Select') {
        operation.data.rules = op.data.rules.map(r => {
          var rule = new Models['SelectRule']().createFromSource(r)
          rule.id = self.getNextId()
          return rule
        })
      }

      operation.id = self.getNextId()
      return operation
    })
  }

  removeOperations () {
    this.ops = []
    this.add('OpenTable', { table: store.getters.table })
  }
}



