import injector from 'vue-inject'
import { HTTP } from '../utilities/http-common'

const Service = {
  query (options) {
    var query = {
      params: {
        start: options.start,
        end: options.end,
        uid: options.uid,
        tableName: options.uid
      }
    }
    return HTTP.get('api/query', query)
  },

  timeline (options) {
    return HTTP.post('api/timeline/run', {
      loginInfo: {
        uid: options.uid,
        gateway: 'https://www2.1010data.com/cgi-bin/gw'
      },
      start: options.startRow || 0,
      end: options.endRow || 10,
      ops: options.ops
    })
  },

  timelineAsMacro (options) {
    return HTTP.post('api/timeline/macro', {
      loginInfo: {
        uid: options.uid
      },
      start: 0,
      end: 0,
      ops: options.ops
    })
  },

  workspaceLoad (uid) {
    return HTTP.get('api/workspace/' + uid)
  },

  workspaceSave (timelines) {
    return HTTP.post('api/workspace', {
      loginInfo: {
        uid: timelines[0].uid
      },
      workspace: {
        timelines: timelines
      }
    })
  },

  workspaceRemove (uid) {
    return HTTP.post('api/workspace/remove/' + uid)
  },

  transform (res) {
    var colDefs = res.data.cols.map((c) => {
      return {
        headerName: (c.title && c.title.length > 0) ? c.title : c.name,
        field: c.name
      }
    })

    var rows = res.data.cols[0].data.map((d, i) => {
      var o = {}
      res.data.cols.forEach((c) => {
        o[c.name] = c.data[i]
      })
      return o
    })

    return {
      columnDefs: colDefs,
      rowData: rows
    }
  },

  transformAgGrid (res) {
    var data = this.transform(res)
    var rowCountDef = {
      headerName: '#',
      // it is important to have node.id here, so that when the id changes (which happens
      // when the row is loaded) then the cell is refreshed.
      valueGetter: 'node.id',
      cellRenderer: (params) => {
        if (params.value !== undefined) {
          return params.value
        } else {
          return '<img src="static/images/loading.gif">'
        }
      }
    }

    data.columnDefs.unshift(rowCountDef)

    return data
  },

  transformSlickGrid (res, start) {
    var colDefs = res.data.cols.map((c) => {
      return {
        name: (c.title && c.title.length > 0) ? c.title : c.name,
        id: c.name,
        field: c.name
      }
    })

    var rows = res.data.cols[0].data.map((d, i) => {
      var o = {}
      res.data.cols.forEach((c) => {
        o[c.name] = c.data[i]
      })
      return o
    })

    rows = rows.map((r, index) => {
      r.index = index + start + 1
      return r
    })

    colDefs.unshift({
      name: 'index',
      id: 'index',
      field: 'index'
    })

    return {
      columnDefs: colDefs,
      rowData: rows
    }
  }
}

injector.service('DiscoveryApi', () => {
  return Service
})



