import Timeline from './timelineModel'
import { store } from '../store'

const state = () => {
  return {
    columns: [],
    duration: 0,
    timeline: new Timeline(store.getters.uid, store.getters.table, `Workbook ${store.getters.indexer}`),
    totalRows: 0
  }
}

const getters = {
  columns: (state) => state.columns,
  duration: (state) => state.duration,
  timeline: (state) => state.timeline,
  totalRows: (state) => state.totalRows
}

const mutations = {
  updateColumns (state, columns) {
    state.columns = columns
  },
  updateDuration (state, duration) {
    state.duration = duration
  },
  updateTimeline (state, timeline) {
    state.timeline = timeline
  },
  updateTimelineName (state, name) {
    state.timeline.name = name
  },
  updateTotalRows (state, totalRows) {
    state.totalRows = totalRows
  }
}

export default {
  state,
  getters,
  mutations
}



