const exports = {}

function requireAll (r) {
  r.keys().forEach(key => {
    if (r(key).default) {
      exports[r(key).default.name] = r(key).default
    } else {
    }
  })
}
requireAll(require.context('../', true, /Model\.js$/))

export default exports



