const exports = {}
function requireAll (r, Vue) {
  r.keys().forEach(key => {
    // install component
    Vue.component(r(key).default.name, r(key).default)
  })
}

function exportAll (r) {
  r.keys().forEach(key => {
    // set for named export
    exports[r(key).default.name] = r(key).default
  })
}

const options = {
  install (Vue) {
    requireAll(require.context('../', true, /\.vue$/), Vue)
  }
}

exportAll(require.context('../', true, /\.vue$/))

export default options
export { exports }



