<template>
  <div v-if="!timeline">
    no timeline
  </div>
  <div v-else class="row timeline">
    <div class="col-md-4">
      <div class="form-group">
        <label for="uid">User Id</label>
        <input v-model="timeline.uid" class="form-control"/>
      </div>
      <vue-tabs @tab-change="handleTabChange" class="ops--tabs" ref="timelineTabs">
        <v-tab title="Timeline">
          <div class="row" v-for="(op, key, index) in timeline.ops" :key="key">
            <div class="col-md-12">
              <div class="row">
                <div class="col-md-12">
                  <component
                    :is="getComponentType(op)"
                    :op="op"
                    :id="id"
                    @addRule="addRule"
                    @freezeAtBoth="freezeAtBoth"
                    @freezeAtColumn="freezeAtColumn"
                    @freezeAtRow="freezeAtRow"
                    @remove="remove"
                    @removeRule="removeRule">
                  </component>
                </div>
              </div>
            </div>
          </div>

          <div class="row text-center">
            <button class="btn btn-default" @click="addCompute">Add Column</button>
            <button class="btn btn-default" @click="addSelect">Add Select</button>
            <button class="btn btn-default" @click="runTimeline">Run Timeline</button>
          </div>
        </v-tab>

        <v-tab title="Json">
          <textarea readonly class="readonly-textarea" v-model="json"></textarea>
        </v-tab>

        <v-tab title="Macro">
          <div class="text-center" v-show="!macro">
            <img src="static/images/loading.gif" alt="loading macro data">
          </div>
          <textarea readonly class="readonly-textarea" v-show="macro" v-model="macro"></textarea>
        </v-tab>
      </vue-tabs>
    </div>
    <div class="col-md-8">
      <div class="row info">
        <div class="col-md-12">
          <span class="badge">Total Rows: {{ totalRows }}</span> <span class="badge">Load Time: {{ duration }} ms</span>
          <div id="slickGrid" class="slickgrid-container">
          </div>
        </div>
      </div>
    </div>

    <context-menu id="context-menu" ref="ctxMenu">
      <li>
        <span>test</span>
      </li>
      <li>
        <span>hello world</span>
      </li>
      <li>
        <span>good bye</span>
      </li>
      <li>
        <span>get swifty</span>
      </li>
    </context-menu>
  </div>
</template>

<script>
import contextMenu from 'vue-context-menu'
import { VueTabs, VTab } from 'vue-nav-tabs'
import { Grid } from 'slickgrid-es6'

export default {
  name: 'timeline',
  components: {
    contextMenu,
    VTab,
    VueTabs
  },
  dependencies: { discoveryApi: 'DiscoveryApi' },
  data: () => {
    return {
      id: undefined,
      currentStart: 0,
      grid: undefined,
      gridOptions: {
      },
      macro: undefined,
      macroLoading: true,
      provider: undefined,
      refreshAtColumn: false,
      refreshAtRow: false,
      timer: undefined
    }
  },
  computed: {
    columns () {
      return this.$store.getters[`timelineModule${this.id}/columns`]
    },
    duration () {
      return this.$store.getters[`timelineModule${this.id}/duration`]
    },
    json () {
      return JSON.stringify(this.timeline, null, 2)
    },
    refreshAt () {
      return this.refreshAtColumn || this.refreshAtRow
    },
    timeline () {
      return this.$store.getters[`timelineModule${this.id}/timeline`]
    },
    totalRows () {
      return this.$store.getters[`timelineModule${this.id}/totalRows`]
    }
  },
  created () {
    this.id = this.$route.params.id - 0

    if (!this.$store.state.timelines.includes(this.id)) {
      this.$router.push('/')
    }

    this.provider = this.createSlickGridProvider()
  },
  mounted () {
    var self = this
    // process on next tick to ensure everything is loaded
    this.$nextTick(() => {
      setTimeout(() => {
        self.grid = self.createSlickGrid()
        self.loadVisibleRowsIntoViewport(true)
      }, 500)
    })
  },
  methods: {
    addCompute () {
      this.timeline.add('Compute')
    },
    addRule (op) {
      this.timeline.addRule(op)
    },
    addSelect () {
      this.timeline.add('Select')
    },
    freezeAtBoth () {
      this.refreshAtColumn = true
      this.refreshAtRow = true
    },
    freezeAtColumn () {
      this.refreshAtColumn = true
    },
    freezeAtRow () {
      this.refreshAtRow = true
    },
    getComponentType (op) {
      return op.constructor.name
    },
    handleTabChange (tabIndex, newTab, oldTab) {
      if (newTab.title === 'Macro') {
        this.macro = undefined
        this.loadMacro()
      }
    },
    loadMacro () {
      var self = this
      this.discoveryApi.timelineAsMacro(self.timeline).then(res => {
        self.macro = res.data
      })
    },
    remove (op) {
      this.timeline.remove(op)
    },
    removeRule (op, rule) {
      this.timeline.removeRule(op, rule)
    },

    // below are grid functions
    createSlickGrid () {
      var grid = new Grid('#slickGrid', this.provider, [], this.gridOptions)

      var self = this

      /** additional grid functions **/
      grid.onContextMenu.subscribe((e) => {
        e.preventDefault()
        self.$refs.ctxMenu.open()
      })

      grid.onScroll.subscribe((e, args) => {
        if (self.timer) {
          clearTimeout(self.timer)
          self.timer = undefined
        }

        self.timer = setTimeout(() => {
          self.loadVisibleRowsIntoViewport(false)
        }, 200)
      })

      return grid
    },
    createSlickGridProvider () {
      var self = this
      var provider = {
        totalRows: 0,
        window: {
          colDefs: [],
          data: [],
          end: 0,
          start: 0
        },
        /** functions **/
        ensureData: (start, end, forceRefresh) => {
          var w = provider.window
          if (end === w.end && start === w.start && !forceRefresh) {
            return
          }

          console.log('load data: ' + start + ' - ' + end)
          provider.getRows({ startRow: start, endRow: end })
        },
        getItem: (index) => {
          var w = provider.window

          var dataIndex = index - w.start
          if (index >= w.start && index <= w.end) {
            return w.data[dataIndex]
          }

          return null
        },
        getItemMetadata: (index) => {
          return null
        },
        getLength: () => {
          // returns the number of data items in the set
          return provider.totalRows
        },
        getRows: (params) => {
          console.log('start:' + params.startRow + ' end:' + params.endRow, params)
          // get current timeline as a new object

          var options = JSON.parse(JSON.stringify(self.timeline))
          Object.assign(options, {
            startRow: params.startRow,
            endRow: params.endRow
          })

          self.discoveryApi.timeline(options).then(res => {
            var o = self.discoveryApi.transformSlickGrid(res, params.startRow)

            provider.totalRows = res.data.totalRows
            provider.window = {
              start: params.startRow,
              end: params.endRow,
              colDefs: o.columnDefs,
              data: o.rowData
            }

            self.$store.commit(`timelineModule${self.id}/updateDuration`, res.data.duration)
            self.$store.commit(`timelineModule${self.id}/updateTotalRows`, res.data.totalRows)
            self.$store.commit(`timelineModule${self.id}/updateColumns`,
              o.columnDefs.filter((c) => {
                return c.name && c.field
              }).map((c) => {
                return { name: c.name.replace(/\r?\n|\r/g, ' '), field: c.field }
              })
            )

            // todo: if coldefs change invalidate all windows
            self.grid.setColumns(o.columnDefs)
            self.grid.updateRowCount()
            self.grid.render()

            if (self.refreshAt) {
              self.$nextTick(() => {
                if (self.refreshAtColumn) {
                  self.refreshColumn(o.columnDefs.length - 1)
                } else if (self.refreshAtRow) {
                  self.refreshRow()
                }
              })
            }
          }, (err) => {
            var msg = (err.data && err.data.message) ? err.data.message : err.statusText
            console.log(msg)
            // need to add alerts
          })
        }
        /** end functions **/
      }

      return provider
    },
    loadVisibleRowsIntoViewport (forceRefresh) {
      var vp = this.grid.getViewport()
      this.provider.ensureData(vp.top, vp.bottom, forceRefresh)
    },

    refreshColumn (columnIndex) {
      this.grid.scrollCellIntoView(this.currentStart, columnIndex)
      this.refreshAtColumn = false
    },
    refreshRow () {
      this.grid.scrollRowIntoView(this.currentStart)
      this.refreshAtRow = false
    },
    runTimeline () {
      var vp = this.grid.getViewport()
      this.currentStart = vp.top
      this.loadVisibleRowsIntoViewport(true)
    }
  }
}
</script>

<style lang="scss">
  .timeline {
    margin-bottom: 30px;
  }
  .info {
    margin: 15px 0;
  }
  .readonly-textarea {
    height: 400px;
    width: 100%;
  }
  .badge {
    background-color: #2c3e50;
    padding: 8px;
  }
  .padding-top {
    padding-top: 15px;
  }
  .ctx-menu {
    font-size: 1em;
    padding: 10px 10px;

    & > li {
      padding: 5px 0;
    }
  }
</style>



